import{_ as e,o as a,c as r,a7 as d}from"./chunks/framework.C5fSpjcB.js";const c=JSON.parse('{"title":"Team Building","description":"","frontmatter":{},"headers":[],"relativePath":"en/awakeners/team-building.md","filePath":"en/awakeners/team-building.md","lastUpdated":1775394001000}'),i={name:"en/awakeners/team-building.md"};function l(o,t,s,n,h,m){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="team-building" tabindex="-1">Team Building <a class="header-anchor" href="#team-building" aria-label="Permalink to &quot;Team Building&quot;">​</a></h1><p>Teams in Morimens consist of up to <strong>4 Awakeners</strong>. Building an effective team requires understanding realm synergy, role distribution, and card interactions.</p><h2 id="team-size" tabindex="-1">Team Size <a class="header-anchor" href="#team-size" aria-label="Permalink to &quot;Team Size&quot;">​</a></h2><ul><li>Maximum of <strong>4 Awakeners</strong> per team.</li><li>You can bring fewer than 4, but there is rarely a reason to do so.</li></ul><h2 id="realm-synergy" tabindex="-1">Realm Synergy <a class="header-anchor" href="#realm-synergy" aria-label="Permalink to &quot;Realm Synergy&quot;">​</a></h2><p>Building a team around a single Designated Realm activates synergy bonuses and ensures your deck is cohesive.</p><table tabindex="0"><thead><tr><th>Realm</th><th>Synergy Focus</th><th>Team Style</th></tr></thead><tbody><tr><td><span class="realm-badge realm-chaos">Chaos</span></td><td>Mix cards from multiple realms; boost Silver Key generation</td><td>Flexible, hybrid compositions</td></tr><tr><td><span class="realm-badge realm-aequor">Aequor</span></td><td>Summon and empower Tentacle entities</td><td>Summon-heavy, board presence</td></tr><tr><td><span class="realm-badge realm-caro">Caro</span></td><td>Create and consume Embryo cards for burst damage</td><td>Combo-oriented, resource management</td></tr><tr><td><span class="realm-badge realm-ultra">Ultra</span></td><td>Gain extra turns from playing multiple cards</td><td>Speed-focused, chain actions</td></tr></tbody></table><h3 id="chaos-flexibility" tabindex="-1">Chaos Flexibility <a class="header-anchor" href="#chaos-flexibility" aria-label="Permalink to &quot;Chaos Flexibility&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><span class="realm-badge realm-chaos">Chaos</span> Awakeners are uniquely flexible. They can be slotted into any realm team without breaking synergy, making them excellent filler picks when you lack a full roster for a given realm.</p></div><h2 id="role-distribution" tabindex="-1">Role Distribution <a class="header-anchor" href="#role-distribution" aria-label="Permalink to &quot;Role Distribution&quot;">​</a></h2><p>A balanced team typically includes:</p><table tabindex="0"><thead><tr><th>Slot</th><th>Recommended Role</th><th>Purpose</th></tr></thead><tbody><tr><td>1</td><td>DPS</td><td>Primary damage dealer</td></tr><tr><td>2</td><td>DPS or Sub-DPS</td><td>Secondary damage or burst</td></tr><tr><td>3</td><td>Support</td><td>Buffs, healing, utility</td></tr><tr><td>4</td><td>Tank or Support</td><td>Survivability or additional utility</td></tr></tbody></table><p>Adjust based on content difficulty. Easier content can run multiple DPS; harder content may require two supports or a tank.</p><h2 id="building-by-realm" tabindex="-1">Building by Realm <a class="header-anchor" href="#building-by-realm" aria-label="Permalink to &quot;Building by Realm&quot;">​</a></h2><h3 id="chaos-teams" tabindex="-1"><span class="realm-badge realm-chaos">Chaos</span> Teams <a class="header-anchor" href="#chaos-teams" aria-label="Permalink to &quot;&lt;span class=&quot;realm-badge realm-chaos&quot;&gt;Chaos&lt;/span&gt; Teams&quot;">​</a></h3><ul><li>Focus on Silver Key generation to activate <a href="./../key-orders/">Key Orders</a> quickly.</li><li>Can borrow strong cards from other realms for a versatile deck.</li><li>Best for players with a diverse roster.</li></ul><p><strong>Recommended Compositions:</strong></p><table tabindex="0"><thead><tr><th>Team</th><th>Members</th><th>Notes</th></tr></thead><tbody><tr><td>#24 Chaos National</td><td>24 / Ramona / Ogier / Lily</td><td>Top-tier Chaos comp</td></tr><tr><td>#24 Deep Sea Variant</td><td>24 / Tulu / Murphy / Shan</td><td>Cross-realm flex</td></tr></tbody></table><h3 id="aequor-teams" tabindex="-1"><span class="realm-badge realm-aequor">Aequor</span> Teams <a class="header-anchor" href="#aequor-teams" aria-label="Permalink to &quot;&lt;span class=&quot;realm-badge realm-aequor&quot;&gt;Aequor&lt;/span&gt; Teams&quot;">​</a></h3><ul><li>Build around Tentacle summoning synergies.</li><li>Prioritize Awakeners whose cards generate or empower Tentacles.</li><li>Strong sustained damage through summon uptime.</li></ul><p><strong>Recommended Compositions:</strong></p><table tabindex="0"><thead><tr><th>Team</th><th>Members</th><th>Notes</th></tr></thead><tbody><tr><td>Deep Sea Double-Carry</td><td>Tulu / Aurita / Celeste / Shan</td><td>Standard Aequor meta</td></tr><tr><td>Tentacle Mixed-Damage</td><td>Miryam / Aurita / Caecus / Murphy</td><td>Tentacle stacking</td></tr><tr><td>Caecus Counter</td><td>Caecus / Hameln / Goliath / Ramona</td><td>Counter-based damage</td></tr><tr><td>Shark-Caecus</td><td>Goliath / Caecus / Celeste / Shan</td><td>Defensive Aequor</td></tr></tbody></table><h3 id="caro-teams" tabindex="-1"><span class="realm-badge realm-caro">Caro</span> Teams <a class="header-anchor" href="#caro-teams" aria-label="Permalink to &quot;&lt;span class=&quot;realm-badge realm-caro&quot;&gt;Caro&lt;/span&gt; Teams&quot;">​</a></h3><ul><li>Revolve around creating Embryo cards and consuming them for powerful effects.</li><li>Requires good hand management and turn planning.</li><li>High burst damage potential when combos align.</li></ul><p><strong>Recommended Compositions:</strong></p><table tabindex="0"><thead><tr><th>Team</th><th>Members</th><th>Notes</th></tr></thead><tbody><tr><td>Uvhash Standard</td><td>Uvhash / Rhea / Aigis / Faint</td><td>Core Caro comp</td></tr><tr><td>Father Comp</td><td>Salvador / Rhea / Aigis / 24 or Ramona</td><td>Shield-counter focus</td></tr><tr><td>#24 Flesh Variant</td><td>24 / Helot or Rhea / Aigis / Salvador</td><td>Burst damage</td></tr></tbody></table><h3 id="ultra-teams" tabindex="-1"><span class="realm-badge realm-ultra">Ultra</span> Teams <a class="header-anchor" href="#ultra-teams" aria-label="Permalink to &quot;&lt;span class=&quot;realm-badge realm-ultra&quot;&gt;Ultra&lt;/span&gt; Teams&quot;">​</a></h3><ul><li>Play as many cards as possible per turn to trigger extra turn effects.</li><li>Low-cost cards and Arithmetica efficiency are critical.</li><li>Snowball potential — the more turns you take, the more damage you deal.</li></ul><p><strong>Recommended Compositions:</strong></p><table tabindex="0"><thead><tr><th>Team</th><th>Members</th><th>Notes</th></tr></thead><tbody><tr><td>Ultra Poison (Beginner)</td><td>Wanda / Nodera / Erica / Nymphia</td><td>Beginner-friendly</td></tr><tr><td>Ultra Starter</td><td>Liz / Erica / Ogier / Doll</td><td>Free characters only</td></tr><tr><td>Ultra Double-C</td><td>Winkle / Erica / Liz / Flex</td><td>Endgame Ultra</td></tr></tbody></table><h2 id="key-synergies" tabindex="-1">Key Synergies <a class="header-anchor" href="#key-synergies" aria-label="Permalink to &quot;Key Synergies&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Synergy</th><th>Characters</th><th>Mechanic</th></tr></thead><tbody><tr><td>Tentacle Stacking</td><td>Tulu + Aurita + Miryam</td><td>Each adds tentacle instances; auto-follow attacks multiply</td></tr><tr><td>Embryo Engine</td><td>Rhea + Aigis</td><td>Rhea devours embryos for healing; Aigis produces/manages them</td></tr><tr><td>Father&#39;s Blood Pool</td><td>Salvador + Rhea</td><td>Rhea copies Salvador&#39;s 2-cost card; HP drain cycle for damage</td></tr><tr><td>Counter Scaling</td><td>Caecus + Nodera</td><td>Caecus E3 defense cards deal counter crit damage; Nodera fills gauge</td></tr><tr><td>#24 Universal</td><td>24 + Any Realm</td><td>Resonance adapts to team realm, always provides matching buffs</td></tr><tr><td>Shield Strike</td><td>Shan + Nodera</td><td>Shan&#39;s shield-based DPS needs Nodera&#39;s support to function</td></tr></tbody></table><h2 id="beginner-priority" tabindex="-1">Beginner Priority <a class="header-anchor" href="#beginner-priority" aria-label="Permalink to &quot;Beginner Priority&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Priority</th><th>Team</th><th>Why</th></tr></thead><tbody><tr><td>1</td><td>Deep Sea SR (Caecus / Pharos / Aurita / Celeste)</td><td>Only needs 4 SR to clear all main story. Tentacles auto-follow, simple to play</td></tr><tr><td>2</td><td>Ultra Poison (Liz / Erica / Ogier / Doll)</td><td>All free/starter characters. Stack poison to win</td></tr><tr><td>3</td><td>Chaos Starter (Initial 4)</td><td>Decent strength, builds game understanding</td></tr></tbody></table><h2 id="general-tips" tabindex="-1">General Tips <a class="header-anchor" href="#general-tips" aria-label="Permalink to &quot;General Tips&quot;">​</a></h2><ul><li><strong>Match realms</strong> where possible for stronger synergy bonuses.</li><li><strong>Bring at least one Support</strong> for sustain in longer fights.</li><li><strong>Check card costs</strong> — a team full of expensive cards will stall if you cannot afford to play them within your 5 Arithmetica per turn.</li><li><strong>Use Chaos Awakeners</strong> to fill gaps in your realm-specific roster.</li></ul><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./list.html">Awakener List</a></li><li><a href="./../cards/">Card System</a></li><li><a href="./../cards/deckbuilding.html">Deckbuilding Guide</a></li><li><a href="./../realms/">Realms Overview</a></li></ul>',38)])])}const b=e(i,[["render",l]]);export{c as __pageData,b as default};
